type Notification =
  | { kind: "toast";  message: string; duration: number }
  | { kind: "modal";  title: string; body: string; actions: string[] }
  | { kind: "banner"; text: string; level: "info" | "warning" | "error" };

function render(n: Notification): string {
  switch (n.kind) {
    case "toast":  return `Toast(${n.duration}ms): ${n.message}`;
    case "modal":  return `Modal: ${n.title} [${n.actions.join("|")}]`;
    case "banner": return `Banner[${n.level}]: ${n.text}`;
  }
}

