  { kind: "banner", text: "Storage at 90%", level: "warning" },
];

for (const n of items) console.log(render(n));

function findUser(id: number): { name: string; email: string } | null {
  const db = [
    { id: 1, name: "Alice", email: "alice@co.com" },
    { id: 2, name: "Bob",   email: "bob@co.com" },
  ];
  return db.find(u => u.id === id) ?? null;
}

function displayUser(id: number): void {
  const user = findUser(id);
  if (user === null) {
    console.log(`User ${id} not found`);
    return;
  }
  // After null check, user is definitely { name, email }
  console.log(`Found: ${user.name} <${user.email}>`);
}

displayUser(1);
displayUser(99);

type Success<T> = { ok: true;  value: T }
type Failure      = { ok: false; error: string; code: number }
type Result<T>    = Success<T> | Failure;

function isSuccess<T>(r: Result<T>): r is Success<T> {
  return r.ok === true;
}

const responses: Result<string>[] = [
  { ok: true,  value: "User created" },
  { ok: false, error: "Not found",   code: 404 },
  { ok: true,  value: "Profile updated" },
  { ok: false, error: "Unauthorized", code: 401 },
];

for (const r of responses) {
  if (isSuccess(r)) {
    console.log(`✓ ${r.value}`);
  } else {
    console.log(`✗ ${r.code}: ${r.error}`);
  }
}

