type Entity = "user" | "order" | "product";
type Action = "created" | "updated" | "deleted";
type EventName = `${Entity}.${Action}`;

type Handler = (payload: Record<string, unknown>) => void;
const handlers = new Map<EventName, Handler[]>();

function on(event: EventName, handler: Handler): void {
  const existing = handlers.get(event) ?? [];
  existing.push(handler);
  handlers.set(event, existing);
}

function emit(event: EventName, payload: Record<string, unknown>): void {
  const hs = handlers.get(event) ?? [];
  for (const h of hs) h(payload);
}

on("user.created",  p => console.log(`User created: ${JSON.stringify(p)}`));
on("order.updated", p => console.log(`Order updated: ${JSON.stringify(p)}`));

emit("user.created",  { id: 42, name: "Alice" });
emit("order.updated", { id: "O1", status: "shipped" });
