type AppAction =
  | { type: "increment"; by?: number }
  | { type: "decrement"; by?: number }
  | { type: "reset" }
  | { type: "set"; value: number };

function reducer(state: number, action: AppAction): number {
  switch (action.type) {
    case "increment": return state + (action.by ?? 1);
    case "decrement": return state - (action.by ?? 1);
    case "reset":     return 0;
    case "set":       return action.value;
    default: {
      const _exhaustive: never = action;
      return state;
    }
  }
}

const actions: AppAction[] = [
  { type: "set", value: 10 },
  { type: "increment", by: 5 },
  { type: "decrement" },
  { type: "reset" },
];

let state = 0;
for (const a of actions) {
  state = reducer(state, a);
  console.log(`${a.type} → ${state}`);
}

