// Approach 2: Enum
enum TrafficLight { Red = "RED", Yellow = "YELLOW", Green = "GREEN" }

function nextState(current: TrafficLight): TrafficLight {
  switch (current) {
    case TrafficLight.Red:    return TrafficLight.Green;
    case TrafficLight.Green:  return TrafficLight.Yellow;
    case TrafficLight.Yellow: return TrafficLight.Red;
  }
}

let light = TrafficLight.Red;
console.log(`Start: ${light}`);
for (let i = 0; i < 4; i++) {
  light = nextState(light);
  console.log(`→ ${light}`);
}

// Exclude certain types from a union
type ExcludeNull<T>      = T extends null | undefined ? never : T;
type OnlyStrings<T>      = T extends string ? T : never;
type Promisify<T>        = T extends Promise<unknown> ? T : Promise<T>;

type SafeValue   = ExcludeNull<string | null | number | undefined>;  // string | number
type StringOnly  = OnlyStrings<string | number | boolean | Date>;    // string
type Async       = Promisify<string | Promise<number>>;              // Promise<string> | Promise<number>

// Runtime demo of the same concept
function filterNull<T>(values: (T | null | undefined)[]): T[] {
  return values.filter((v): v is T => v !== null && v !== undefined);
}

const mixed = ["Alice", null, "Bob", undefined, "Carol", null];
const clean = filterNull(mixed);
console.log(`Original: ${mixed.length} items`);
console.log(`Cleaned: ${clean.length} items: ${clean.join(", ")}`);

type AuthState =
  | { status: "loading" }
  | { status: "unauthenticated" }
  | { status: "authenticated"; user: { id: number; name: string; plan: string }; token: string }
  | { status: "error"; message: string; retryable: boolean };

function renderAuthUI(state: AuthState): string {
  switch (state.status) {
    case "loading":         return "⏳ Loading...";
    case "unauthenticated": return "🔐 Please sign in";
    case "authenticated":   return `👋 ${state.user.name} (${state.user.plan})`;
    case "error":           return `❌ ${state.message}${state.retryable ? " — tap to retry" : ""}`;
  }
}

const states: AuthState[] = [
  { status: "loading" },
  { status: "unauthenticated" },
  { status: "authenticated", user: { id: 1, name: "Alice", plan: "pro" }, token: "tok_xyz" },
  { status: "error", message: "Session expired", retryable: true },
];

for (const s of states) console.log(renderAuthUI(s));
